	.TITLE	ICONEOV	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SM8		; df diverses	.REF	BIOS		; df bios	.REF	NTREL		; df noyau temps rel	.REF	GESMEM		; df gestionnaire de mmoire	.REF	FOS		; df file operating system	.REF	LIB		; df librairie	.REF	DRIVERS		; df drivers	.INS	ICODEF	.REV	ICOREV,ICOVERS; Variables pour une macro; ------------------------	.LOC	0OLIMAC:	.BLKB	LBUEXE		; commande macro (+ paramtres)OPAMAC:	.BLKB	LBUEXE		; buffer pour un paramtreOPTMAC:	.BLKB	2		; ^relatif dans OBUMACOLGMAC:	.BLKB	2		; lg max dans OBUMACOCHMAC:	.BLKB	2		; canal fichier macroOBUMAC:	.BLKB	LGBLK		; buffer pour fichier macroLGZMAC:; Programme; ---------	.LOC	0START:	JUMP	10$	.LOC	8	JUMP	RETEXE10$:	LOAD.W	(A6)+OHISTI,#-1	; pas encore d'histoire	CALL	AFMENU		; affiche le bon menu	LIB	?GCHKEY		; D6 <-- canal du clavier	LOAD.W	(A6)+OCHKEY,D6	CALL	INIDEF		; lit ICONE.LIST	JUMP,NE	FATERR	CALL	INIDIS		; init paramtres display	JUMP,NE	FATERR	LOAD.B	D3,#EOP	LIB	?AFCAR		; efface toute la fentre	.IF	CLE	CALL	AFPSOS		; met "PSos rev" tout en haut	CALL	AFCADRE		; met dj le cadre; Tente d'excuter la macro de dmarrage SYS_BOOT.CLE situe; sur #MM0: (lors d'un dmarrage sur le rseau, ce n'est pas; possible).	LOAD.L	A3,#R16"SYSMA1	; tente d'excuter la macro	CALL	COPMACRO	; de dmarrage locale ...	JUMP,EQ LOOPM		; oui => LOOPM	COMP.W	D7,#ERFDNE	; macro n'existe pas ?	JUMP,EQ LOOP		; oui => LOOP	COMP.W	D7,#ERUNNI	; unit #MM0: n'existe pas ?	JUMP,NE FATERR		; non => FATERR; Lors d'un dmarrage par le rseau, tente d'excuter la macro; personnalise SYS_numro.CLE	BIOS	?GETMACHINE	AND.L	D4,#H'FFFFFF	; D4 <-- numro de la machine	LOAD.L	D3,D4	LOAD.L	A3,#R16"SYSMA2+POSMA2	CALL	PUTNUM		; ajoute le numro dans le nom	LOAD.B	(A3+),#'.	; ajoute l'extension .CLE	LOAD.B	(A3+),#'C	LOAD.B	(A3+),#'L	LOAD.B	(A3+),#'E	CLR.B	(A3)		; termine par <0>	LOAD.L	A3,#R16"SYSMA2	CALL	COPMACRO	JUMP,EQ LOOPM	COMP.W	D7,#ERFDNE	JUMP,NE FATERR; Si cette macro n'existe pas, tente d'excuter la macro; gnrale SYS_REMOTE.CLE	LOAD.L	A3,#R16"SYSMA3	; tente d'excuter la macro	CALL	COPMACRO	; de dmarrage distante ...	JUMP,EQ LOOPM	COMP.W	D7,#ERFDNE	JUMP,NE FATERR	JUMP	LOOP	.ENDIF	.INS	ICOMAIN	.INS	ICOMACROFATERR:	PUSH.W	D7		; sauve l'erreur	LIB	?AFCR		; passe  la ligne	POP.W	D7		; reprend l'erreur	LIB	?AFERROR	; affiche l'erreur	LIB	?GETCAR		; attend une toucheRETOUR:	LOAD.L	A0,(A6)+OADRQU	JUMP	(A0); Insertion des zones dtectes; -----------------------------;--------\; FRAPPE  >;========/; Frappe quelques caractres en fonction de l'icone ou du; fichier slectionn.; in	D3.B		zro => liste fichiers ncessaire;	(A6)+OLSTII.W	rang de l'icone  frapper; out	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFRAPPE:	INC.W	(A6)+OHISTL	; monte dans l'arbre	TEST.B	(A6)+OFLAGS:#BICONE	JUMP,BS	FLICONE	TEST.B	(A6)+OFLAGS:#BLIST	JUMP,BC	FICONE	TEST.B	(A6)+OFLAGS:#BTEXT	JUMP,BS	FTEXT	JUMP	FFICHIER;--------\; FICONE  >;--------/; Frappe un nom de programme en fonction de l'icone ; slectionn.; in	D3.B		zro => liste fichiers ncessaire;	(A6)+OLSTII.W	rang de l'icone  frapper; out	(A6)+OMEMII.W	rang de l'icone frapp;	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFICONE:	PUSHM.L	D0,D2,D3,D4,A3,A4	LOAD.B	D0,D3		; D0 <-- liste ncessaire ?	LOAD.W	D4,(A6)+OLSTII	; D4 <-- icone slectionn	LOAD.W	(A6)+OMEMII,D4	CALL	SYNSRC		; A4 <-- ^dfinition corresp.	JUMP',NE 90$	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- saute le numro	EX.L	A4,A3	JUMP',NE 90$		; si rien aprs => 90$	CLR.B	(A6)+OBUEXE	; ligne de commande vide	CALL	EXCOMM		; excute une commande90$:	CALL	AFCOMM		; affiche la commande	POPM.L	D0,D2,D3,D4,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; EXCOMM  >;========/; Excute une commande LIST ou ICONE prcde ventuellement; d'une chane  insrer.; in	A4.L	^["car"] [mot-clef commande];	D0.B	zro  => liste ncessaire; out	D7.W	zro  => fini;		autre => pas fini; mod	D7.WEXCOMM:	PUSHM.L	D2,D3,A3,A4	CLR.W	D7		; D7 <-- fini	COMP.B	(A4),#'"	; chane  insrer ?	JUMP,NE	40$		; non => 40$				; oui =>	CALL	GETLAST		; D3 <-- dernier caractre frapp	COMP.B	D3,#CARMARK	; dj termin par une marque ?	JUMP',NE 10$		; non => 10$	CALL	DETRUIT		; oui => enlve-la10$:	INC.L	A4		; A4 <-- saute le 1er guillement	CLR.B	D2		; D2 <-- dernier car. frapp20$:	LOAD.B	D3,(A4+)	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	90$	COMP.B	D3,#'"		; fin commande ?	JUMP',EQ 30$	COMP.B	D3,#'|	JUMP',EQ 25$	CALL	INSERT		; "frappe" un caractre	LOAD.B	D2,D3		; D2 <-- dernier car. frapp	JUMP	20$25$:	LOAD.B	D2,#SPACE	; si "blabla|" => n'ajoute pas espace	JUMP	20$30$:	COMP.B	D2,#SPACE	; espace frapp en dernier ?	JUMP',EQ 32$		; oui => 32$	LOAD.B	D3,#SPACE	; non =>	CALL	INSERT		; "frappe" un espace32$:	LOAD.B	D3,#CARMARK	CALL	INSERT		; insre une marque35$:	LOAD.B	D3,(A4+)	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	90$	COMP.B	D3,#SPACE	JUMP,EQ	35$	COMP.B	D3,#TAB	JUMP,EQ	35$	DEC.L	A4		; A4 <-- ^mot-clef40$:	LOAD.B	D3,(A4)		; D3 <-- 1re lettre commande	LIB	?MINMAJ		; D3 <-- lettre majuscule	COMP.B	D3,#'L		; LIST ?	JUMP',EQ 60$		; oui => 60$	COMP.B	D3,#'T		; TEXT ?	JUMP',EQ 65$		; oui => 65$	COMP.B	D3,#'I		; ICONE ?	JUMP',EQ 70$		; oui => 70$	JUMP'	90$60$:	CALL	EXLIST	JUMP'	90$65$:	CALL	EXTEXT	JUMP'	90$70$:	CALL	EXICONE;	JUMP'	90$90$:	POPM.L	D2,D3,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; EXLIST  >;--------/; LIST: Affiche une liste de fichiers.; in	A4.L	^mot-clef LIST;	D0.B	zro => liste ncessaire; out	D7.W	zro  => fini;		autre => pas fini; mod	D7.WEXLIST:	PUSHM.L	D3,D4,A4	CLR.W	D740$:	LOAD.B	D3,(A4+)	; cherche dbut critre	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	90$	COMP.B	D3,#']	JUMP,EQ	90$	COMP.B	D3,#'"		; dbut critre ?	JUMP,NE	40$		; non => 40$	LOAD.L	A3,A4		; A3 <-- ^dbut critre45$:	LOAD.B	D3,(A4+)	; cherche fin critre	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	90$	COMP.B	D3,#']	JUMP,EQ	90$	COMP.B	D3,#'"		; fin critre ?	JUMP,NE	45$		; non => 45$50$:	LOAD.B	D3,(A4+)	; cherche dbut dfaut	JUMP',EQ 60$	COMP.B	D3,#CR	JUMP',EQ 60$	COMP.B	D3,#']	JUMP',EQ 60$	COMP.B	D3,#'"		; dbut dfaut ?	JUMP,NE	50$		; non => 50$60$:	DEC.L	A4		; A4 <-- ^guillemet/terminateur	TEST.B	D0		; liste ncessaire ?	JUMP,NE	80$		; non => 80$	CALL	AFCOMM		; affiche la commande	CALL	AFLIST		; affiche la liste ...	COMP.W	D7,#1		; excution immdiate ?	JUMP',EQ 70$		; oui => 70$	COMP.W	(A6)+OSRCNN,#2	; au moins deux fichiers ?	JUMP',LO 75$		; non => 75$	LOAD.W	D4,(A6)+OLSTII	CALL	INVERSE		; montre un fichier	LOAD.W	D7,#1		; D7 <-- pas fini (manque file)	JUMP	90$70$:	LIB	?IFMOUSE	; D4 <-- position de la souris	JUMP',NE 80$	CALL	DETECTE		; cherche o est la souris	JUMP',NE 80$		; si pas dans qq chose => 80$	LOAD.W	(A6)+OLSTII,D4	CALL	INVERSE		; dessine icone/fichier slectionn	LOAD.B	D3,#1		; D3 <-- excution immdiate	CALL	FRAPPE		; frappe tout de suite	JUMP'	80$75$:	TEST.W	(A6)+OSRCNN	; au moins un fichier ?	JUMP',EQ 80$		; non => 80$	PUSH.W	(A6)+OLSTII	CLR.W	(A6)+OLSTII	; slectionne le seul existant	CALL	FFICHIER	; "frappe" le premier fichier	POP.W	(A6)+OLSTII80$:	CLR.W	D7		; D7 <-- ok (c'est fini)90$:	POPM.L	D3,D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; EXTEXT  >;--------/; TEXT: Affiche une liste de textes.; in	A4.L	^mot-clef TEXT;	D0.B	zro  => liste ncessaire; out	D7.W	zro  => fini;		autre => pas fini; mod	D7.WEXTEXT:	PUSHM.L	D3,D4,A4	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- saute mot-clef	EX.L	A4,A3	TEST.B	D0		; liste ncessaire ?	JUMP',NE 80$		; non => 80$	CALL	AFCOMM		; affiche la commande	CALL	AFTEXT		; affiche les textes ...	COMP.W	D7,#1		; excution immdiate ?	JUMP',EQ 80$		; oui => 80$	COMP.W	(A6)+OSRCNN,#2	; au moins deux textes ?	JUMP',LO 75$		; non => 75$	LOAD.W	D4,(A6)+OLSTII	CALL	INVERSE		; montre un texte	LOAD.W	D7,#1		; D7 <-- pas fini (manque file)	JUMP'	90$75$:	TEST.W	(A6)+OSRCNN	; au moins un texte ?	JUMP',EQ 80$		; non => 80$	PUSH.W	(A6)+OLSTII	CLR.W	(A6)+OLSTII	; slectionne le seul existant	CALL	FLICONE		; "frappe" le premier texte	POP.W	(A6)+OLSTII80$:	CLR.W	D7		; D7 <-- ok (c'est fini)90$:	POPM.L	D3,D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; EXICONE >;--------/; ICONE: Affiche une liste d'icones.; in	A4.L	^mot-clef ICONE;	D0.B	zro => liste ncessaire; out	D7.W	zro  => fini;		autre => pas fini; mod	D7.WEXICONE:	PUSHM.L	D3,D4,A4	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- saute mot-clef	EX.L	A4,A3	TEST.B	D0		; liste ncessaire ?	JUMP',NE 80$		; non => 80$	CALL	AFCOMM		; affiche la commande	CALL	AFLICONE	; affiche les icones ...	COMP.W	D7,#1		; excution immdiate ?	JUMP',EQ 80$		; oui => 80$	COMP.W	(A6)+ONBIC,#2	; au moins deux icones ?	JUMP',LO 75$		; non => 75$	COMP.W	(A6)+OHISTL,#1	; premier niveau ?	JUMP',NE 40$		; non => 40$	LOAD.W	(A6)+OHISTI,(A6)+OMEMII ; oui => mmorise l'histoire40$:	LOAD.W	D4,(A6)+OLSTII	CALL	INVERSE		; montre un icone	LOAD.W	D7,#1		; D7 <-- pas fini (manque file)	JUMP'	90$75$:	TEST.W	(A6)+ONBIC	; au moins un icone ?	JUMP',EQ 80$		; non => 80$	PUSH.W	(A6)+OLSTII	CLR.W	(A6)+OLSTII	; slectionne le seul existant	CALL	FLICONE		; "frappe" le premier icone	POP.W	(A6)+OLSTII80$:	CLR.W	D7		; D7 <-- ok (c'est fini)90$:	POPM.L	D3,D4,A4	TEST.W	D7		; retour EQ/NE	RET;---------\; FLICONE  >;---------/; Frappe un nom en fonction de l'icone slectionn  la fin; de la ligne de commande.; in	(A6)+OLSTII.W	rang de l'icone  frapper;	(A6)+OPTNIC.L	^numros;	(A6)+OPTLIC.L	^noms; out	(A6)+OMEMLI.n	numro de l'icone frapp;	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFLICONE:	PUSHM.L	D0,D2,D3,D4,A3,A4,A5	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^commande actuelle	CLR.W	D7		; D7 <-- fini05$:	LOAD.B	D3,(A3+)	JUMP',EQ 10$	COMP.B	D3,#CARMARK	JUMP,NE	05$	TEST.B	(A3)		; qq chose aprs la marque ?	JUMP,NE	90$		; oui => 90$ (n'ajoute rien)10$:	LOAD.L	A4,(A6)+OPTNIC	; A4 <-- ^numros	LOAD.L	A3,(A6)+OPTLIC	; A3 <-- ^noms	LOAD.W	D4,(A6)+OLSTII	; D4 <-- icone slectionn	COMP.W	D4,#-1	JUMP,EQ	90$20$:	TEST.W	D4		; rang atteint ?	JUMP',EQ 30$		; oui => 30$	DEC.W	D4	EX.L	A3,A4	LIB	?SKPNAM		; A4 <-- ^numro suivant	EX.L	A4,A3	CALL	SKPNAME		; A3 <-- ^nom suivant	JUMP	20$30$:	LOAD.L	A5,#(A6)+OMEMLI	; A5 <-- ^buffer pour mm .choix35$:	LOAD.B	D3,(A4+)	JUMP',EQ 38$	COMP.B	D3,#CR	JUMP',EQ 38$	COMP.B	D3,#SPACE	JUMP',EQ 38$	LOAD.B	(A5+),D3	; mmorise le numro (en ASCII)	JUMP	35$38$:	CLR.B	(A5)		; termine le numro	LOAD.L	A4,A3	COMP.B	(A4),#'[	; commande ?	JUMP',NE 60$		; non => 60$				; oui =>	INC.L	A4		; A4 <-- saute le "["	CLR.B	D0		; D0 <-- liste ncessaire	CALL	EXCOMM		; excute la commande entre [ ]	JUMP'	90$60$:	COMP.B	(A4),#'"	; chane ?	JUMP',NE 90$		; non => 90$				; oui =>	INC.L	A4		; A4 <-- saute le guillemet65$:	LOAD.B	D3,(A4+)	JUMP',EQ 90$	COMP.B	D3,#CR	JUMP',EQ 90$	COMP.B	D3,#'"	JUMP',EQ 90$	CALL	INSERT		; commande <-- nom de fichier	JUMP	65$90$:	CALL	AFCOMM		; affiche la commande	POPM.L	D0,D2,D3,D4,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET;---------\; FTEXT    >;---------/; Frappe un nom en fonction du texte slectionn  la fin; de la ligne de commande.; in	(A6)+OLSTII.W	rang du texte  frapper;	(A6)+OPTNIC.L	^textes;	(A6)+OPTLIC.L	^noms; out	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFTEXT:	PUSHM.L	D0,D2,D3,D4,A3,A4,A5	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^commande actuelle	CLR.W	D7		; D7 <-- fini05$:	LOAD.B	D3,(A3+)	JUMP',EQ 10$	COMP.B	D3,#CARMARK	JUMP,NE	05$	TEST.B	(A3)		; qq chose aprs la marque ?	JUMP,NE	90$		; oui => 90$ (n'ajoute rien)10$:	LOAD.L	A3,(A6)+OPTLIC	; A3 <-- ^noms	LOAD.W	D4,(A6)+OLSTII	; D4 <-- texte slectionn	COMP.W	D4,#-1	JUMP,EQ	90$20$:	TEST.W	D4		; rang atteint ?	JUMP',EQ 30$		; oui => 30$	DEC.W	D4	CALL	SKPNAME		; A3 <-- ^nom suivant	JUMP	20$30$:	LOAD.L	A4,A3	COMP.B	(A4),#'[	; commande ?	JUMP',NE 60$		; non => 60$				; oui =>	INC.L	A4		; A4 <-- saute le "["	CLR.B	D0		; D0 <-- liste ncessaire	CALL	EXCOMM		; excute la commande entre [ ]	JUMP'	90$60$:	COMP.B	(A4),#'"	; chane ?	JUMP',NE 90$		; non => 90$				; oui =>	INC.L	A4		; A4 <-- saute le guillemet65$:	LOAD.B	D3,(A4+)	JUMP',EQ 90$	COMP.B	D3,#CR	JUMP',EQ 90$	COMP.B	D3,#'"	JUMP',EQ 90$	CALL	INSERT		; commande <-- nom de fichier	JUMP	65$90$:	CALL	AFCOMM		; affiche la commande	POPM.L	D0,D2,D3,D4,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET;---------\; FFICHIER >;---------/; Frappe un nom en fonction du fichier slectionn  la fin; de la ligne de commande.; in	(A6)+OLSTII.W	rang du fichier  frapper; out	(A6)+OMEMFI.n	nom du fichier frapp;	D7.W		zro  => fini;			autre => pas fini; mod	D4.W, D7.WFFICHIER:	PUSHM.L	D3,D4,A3,A4,A5	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^commande actuelle05$:	LOAD.B	D3,(A3+)	JUMP',EQ 10$	COMP.B	D3,#CARMARK	JUMP,NE	05$	TEST.B	(A3)		; qq chose aprs la marque ?	JUMP',NE 90$		; oui => 90$ (n'ajoute rien)10$:	LOAD.W	D4,(A6)+OLSTII	; D4 <-- fichier slectionn	CALL	LSTSRC		; A4 <-- ^nom du fichier	JUMP',NE 90$	LOAD.B	D3,(A4)		; D3 <-- 1er caractre fichier/dfaut	COMP.B	D3,#'@	JUMP',EQ 30$	COMP.B	D3,#'#	JUMP',EQ 30$	COMP.B	D3,#'0	JUMP',LO 90$	COMP.B	D3,#'9	JUMP',LS 30$	COMP.B	D3,#'A	JUMP',LO 90$	COMP.B	D3,#'Z	JUMP',HI 90$30$:	LOAD.L	A5,#(A6)+OMEMFI40$:	LOAD.B	D3,(A4+)	JUMP',EQ 50$	COMP.B	D3,#CR	JUMP',EQ 50$	COMP.B	D3,#'"	JUMP',EQ 50$	CALL	INSERT		; commande <-- nom de fichier	LOAD.B	(A5+),D3	; mmorise le nom du fichier	JUMP	40$50$:	CLR.B	(A5)		; termine la mmorisation90$:	CALL	AFCOMM		; affiche la commande	CLR.W	D7		; D7 <-- toujours ok	POPM.L	D3,D4,A3,A4,A5	TEST.W	D7		; retour EQ/NE	RET; Modules; ----